<style>
/* VIGOSHOP - CSS variables for checkout-form */
:root {
	/* quantity button */
	--size-cf-qty-border: 2px;
	--size-cf-qty-border-radius: 5px;
	--clr-cf-qty-border: #f09831;
	--clr-cf-qty-bg: #fff5e3;
	--clr-cf-qty-discount: white;
	--clr-cf-qty-discount-bg: #f09831;
	--clr-cf-qty-free-shipping-bg: #47b426;

	/* property button (size, type etc.) */
	--size-cf-property-border: 3px;
	--size-cf-property-border-radius: 5px;
	--clr-cf-property: #f09831;
	--clr-cf-property-bg: #fff5e3;

	/* property button (color) */
	--size-cf-property-color-border: 3px;
	--size-cf-property-color-border-radius: 5px;
	--clr-cf-property-color: #f09831;
	--clr-cf-property-color-bg: white;

	/* property button (bundle colors) */
	--size-cf-property-bcolor-border: 3px;
	--size-cf-property-bcolor-border-radius: 5px;
	--clr-cf-property-bcolor: #f09831;
	--clr-cf-property-bcolor-bg: white;

	/* property button (icon or image) */
	--size-cf-property-icon-border: 3px;
	--size-cf-property-icon-border-radius: 5px;
	--clr-cf-property-icon: #f09831;
	--clr-cf-property-icon-bg: white;

	/* price */
	--clr-cf-rp: #ca232c;
	--clr-cf-op: #707070;

	/* cart button */
	--size-cf-cart-btn-radius: 4px;
	--clr-cf-cart-btn: white;
	--clr-cf-cart-btn-bg: #24B800;
	--clr-cf-cart-btn-gr-1: #3EC000;
	--clr-cf-cart-btn-gr-2: #00AC00;
	--clr-cf-cart-btn-shadow: #009900;
	--clr-cf-cart-btn-border: #009900;
}
