	<style>
/* Auto shared resourse - "Cart CSS" */
html, body {
  touch-action: manipulation;
}

form.hs-cf .quantity-picker,
form.hs-cf .checkmark,
form.hs-cf .active_quantity_button,
form.hs-cf .quantity_button,
form.hs-cf .custom_qty .product_price_basic,
form.hs-cf .hs-property-button { 
	border-radius: 4px!important;
	border-color: #ddd;
}
.hs-cf tr:has(.product_price_basic) {
	display: flex;
	margin-top: 10px;
	column-gap: 10px;
}
.hs-cf tr:has(.best-offer-banner) {margin-top: 20px;}
.custom_qty table {border-spacing: 0!important; margin-top: 10px;} 

form.hs-cf .checkmark-checked {
	border: var(--clr-upsell, #25b800) solid 2px !important;
    background-color: var(--clr-upsell, #25b800) !important;
}
form.hs-cf .hs-rp.hs-rp-checked {
	border: var(--clr-upsell, #25b800) solid 2px !important;
    background-color: var(--clr-upsell-light, #F2FEEE) !important;
}
form.hs-cf .hs-rp.hs-rp-checked .quantity-picker {
	border: var(--clr-upsell, #25b800) solid 2px !important;
    background-color: var(--clr-upsell, #25b800) !important;
	color: #fff;
	font-weight: 600;
	outline-color: var(--clr-upsell, #25b800);
}

/* For auto shared resourse "Payment and delivery features" */
.paydel-features {
	display: flex;
	flex-direction: column;
	row-gap: 0.25rem;
	margin-top: 1rem;
}
.paydel-features__item {
	display: flex;
	align-items: center;
	column-gap: 0.5rem;
	font-size: 14px;
	text-align: left;
}
.paydel-features__icon {height: 25px;width: 25px;}
.paydel-features .--accent {color: #47b426; fill: #47b426;}
.paydel-features__text.--accent {font-weight: bold;}

/* START - CSS cart QTN 6 */

/* form.hs-cf .hs-cf-pl-bottom div, */
form.hs-cf .banner-save {font-size: clamp(10px, 14vw/4.5, 14px)!important;}

@media only screen and (max-width: 600px) {
	.hs-cf tr:has(.product_price_basic) {column-gap: 6px;}
	.customer-favorite {
		display: flex;
		flex-wrap: wrap;
		margin: auto;
	}
	.custom_qty .best-offer-banner { /*  */
		transform: translateY(-70%) !important;
	}
	.custom_qty_variation {
		display: none;
	}
	.property-dropdown {
		-webkit-text-fill-color: black;
	}
}

.property-dropdown {
	margin-top:.5rem;
	margin-bottom:.5rem;
}
.custom_qty .best-offer-banner { /*  */
	top: unset!important;
	font-size: 9.5px!important;
	transform: translateY(-65%);
	width: calc(100% - 8px);
	max-width: fit-content;
	padding: 2px 4px!important;
	font-weight: 600!important;
	-webkit-text-fill-color: white!important;
}
/* END - CSS cart QTN 6 */

.custom_qty > .quantity {padding-left: 0!important;}
.hs-cf .hs-cf-price-orig,
.hs-cf .hs-cf-price-red {line-height: 1.2;}

.shipping-price {text-align: right;padding-bottom: 5px;}
.hs-cf-cart-btn::after{padding-top:0rem!important}
.hs-cf .hs-cf-cart-btn-text {
	display: inline-block;
	top: 50%;
	transform: translateY(-50%);
	width: calc(100% - 60px);
}

.hs-cf-cart-btn {line-height: 0;}
.hs-cf-cart-btn-text {line-height: 1;}
@media (max-width: 520px) {
	.hs-cf .hs-cf-cart-btn-text {font-size: 82%;}
	.shipping-price {font-size: clamp(12px, 14vw/3.75, 14px);}
}

@media screen and (max-width:768px){.hs-cf-price-left{font-size:1.2rem}}
@media screen and (max-width: 375px) {
	.hs-cf .hs-cf-price-left {
		padding-left: 0;
	}
	.hs-cf .hs-cf-pl-bottom div {
		/* font-size: 85%; */
		font-size: clamp(14px, 17vw/3.75, 17px);
	}
	.hs-cf .hs-cf-price-orig {
		/* font-size: 20px; */
		font-size: clamp(18px, 20vw/3.75, 20px);
	}
	.hs-cf .hs-cf-price-red {
		/* font-size: 28px; */
		font-size: clamp(23px, 27vw/3.75, 27px);
		margin-left: 0;
	}
}

/*Hide Trustpilot*/
.trustpilot-widget {display:none !important;}

/*UPSELL CSS*/
.hs-rp-txt {text-align:left; margin-top:10px;}
form.hs-cf .hs-rp-description {font-size: 0.938em; font-weight:400;}
form.hs-cf .hs-rp .hs-rp-checkbox-w {font-size: 14px;padding-top: 0;height: 44px;text-align:left; margin: auto 0 0 0;justify-content: flex-start!important;}
form.hs-cf .hs-rp .remove-upsell-icon {min-width: 15px;}
form.hs-cf .hs-rp {padding: 10px; justify-content: space-between;}
form.hs-cf .hs-rp .add-purchase-text {text-align: center;}
form.hs-cf .hs-rp.hs-rp-checked .add-purchase-text {font-weight: 600;text-align: center;}
form.hs-cf .hs-rp-title-and-desc {font-size: clamp(13px, 15vw/4.79, 15px);line-height: 1.2;}
@media screen and (max-width:768px) {
	.hs-rp .add-purchase-text {margin-top: 0;}
	form.hs-cf .hs-rp-wrapper {padding-inline: 0 !important;}
}
/* @media screen and (max-width:539px) {
	form.hs-cf .hs-rp .hs-rp-checkbox-w > * {margin-right: 8px;}
} */

form.hs-cf {--checkmark-size: 40px;}
@media screen and (max-width:768px) {form.hs-cf {--checkmark-size: 30px;}}
form.hs-cf .hs-rp .quantity-picker {width: calc(var(--checkmark-size) + 20px);}

form.hs-cf .hs-rp .checkmark p {font-size: calc(var(--checkmark-size) - 68%); padding-inline: 5px;}
form.hs-cf .hs-rp .hs-rp-dropdown-quantity {height: auto; margin-block: 0;}

form.hs-cf .hs-rp {
	--gap: 10px;
}

form.hs-cf .hs-rp-description,
form.hs-cf .hs-rp-both-prices {
	margin-top: var(--gap, 10px);
}

form.hs-cf .hs-rp-img-desc {
	display: grid;
	grid-template-columns: auto 1fr;
	grid-template-rows: auto auto;
	gap: var(--gap, 10px);
}
form.hs-cf .hs-rp-desc-text {
	font-size: 1.15em;
}
form.hs-cf .hs-rp-img-w {
	grid-row: 1 / -1;
	width: 100%!important;
	float: unset;
	margin-right: unset;
}
form.hs-cf .hs-rp-img {
	width: clamp(170px, 189vw/19.2, 189px);
	min-width: 100px;
}
form.hs-cf .hs-rp .quantity-picker {
	font-size: 15px;
}

/* Brand color variables are managed in the shortcode "nm-branded-style" */
form.hs-cf .hs-rp .quantity-picker {
	border: var(--clr-upsell, #25b800) solid 2px !important;
	background-color: var(--clr-upsell, #25b800) !important;
	color: #fff;
	font-weight: 600;
	outline-color: var(--clr-upsell, #25b800);
}

form.hs-cf .hs-rp.hs-rp-checked {
	border: var(--clr-upsell, #25b800) solid 2px !important;
	background-color: var(--clr-upsell-light, #F2FEEE) !important;
}
form.hs-cf .hs-rp .checkmark {
	border-color: var(--clr-upsell, #25b800);
	background-color: var(--clr-upsell, #25b800) !important;
}
form.hs-cf .hs-rp .checkmark-checked {
	background-color: transparent !important;
	border: none !important;
}
form.hs-cf .hs-rp .checkmark-checked p {
	padding: 0;
}
form.hs-cf .hs-added-text {
	color: var(--clr-upsell, #25b800) !important;
}
form.hs-cf .checkmark-added {
	background-color: var(--clr-upsell, #25b800) !important;
}

/* NM - Adaptation for UPSELL CSS */
/* (Adaptation for other templates can be found in the shortcodes «ot-style-fix» & «nld-style-fix») */
@media screen and (min-width:1024px) and (max-width:1439px) {
	[data-tpl="nmm"] form.hs-cf .hs-rp.hs-rp-checked .hs-rp-checkbox-w {
		grid-column: 1 / -1;
		justify-content: center !important;
	}
}

@media screen and (max-width:539px) {
	[data-tpl="nmm"] form.hs-cf .hs-rp .hs-rp-checkbox-w {
		grid-column: 1 / -1;
		justify-content: center !important;
	}
	[data-tpl="nmm"] form.hs-cf .hs-rp-img {
		width: 120px
	}
}
/* end NM - Adaptation for UPSELL CSS */



