/* Change the price and discount style */
.hs-cf .price-calculator {
  display: flex;
  flex-direction: row-reverse;
  gap: var(--gap, 0.5rem);
  align-items: center;
  justify-content: flex-end;
}

.hs-cf .hs-cf-row {--gap: clamp(8px, 16vw/3.75, 16px); gap: var(--gap, 0.5rem); height: auto; margin-top: 1.25rem;}
.hs-cf-pl-bottom::before {display: none;}
.hs-cf .hs-cf-price-red {font-size: 30px;font-size: clamp(23px, 30vw/3.75, 30px);}
.hs-cf .hs-cf-price-orig {
  font-size: 22px;
	margin-top: 0;
}
form.hs-cf .hs-cf-pl-bottom > div {font-size: 18px;}
form.hs-cf .hs-cf-pl-bottom {
	height: auto;
	background-color: #ca232c;
	padding: .15rem .5rem;
}
/* END Change the price and discount style */

/* START - Different price for variations */
/* ========================================================================== */
/* color buttons */
form.hs-cf .hs-cf-property-color .variation-price:not(:empty) {
	padding-inline: 0.15em;
}

form.hs-cf .hs-cf-property-color:not(:has(.variation-price:empty)) {
	height: calc(2em + 1.55em);
	min-width: 3.5em;
	width: auto;
	max-width: 100%;
	border-radius: 5px;
	border: 2px solid #0000001a;
	margin-bottom: 0.35em;
	position: relative;
	padding: 0;
	z-index: 1;
}

form.hs-cf .hs-cf-property-color .variation-price:not(:empty)::after {
	content: "";
	border-top: 1.5px solid #0000001a;
	height: 50%;
	position: absolute;
	width: 100%;
	bottom: 0;
	background-color: #ffffffaa;
	z-index: -1;
	border-radius: 0 0 0.15em 0.15em;
}

/* icon buttons */
form.hs-cf .hs-cf-property-icon:not(:has(.variation-price:empty)) {
	height: calc(4.7em + 1.55em);
	min-width: 4.7em;
	width: auto;
	background-size: contain!important;
	background-repeat: no-repeat!important;
	background-position-y: 0!important;
	border: var(--size-cf-property-icon-border) solid #0000001a;
	z-index: 1;
}

form.hs-cf .hs-cf-property-icon .variation-price:not(:empty)::after {
	content: "";
	border-top: 1.5px solid #0000001a;
	background-color: #ffffffaa;
	height: 1.55em;
	width: 100%;
	position: absolute;
	z-index: -1;
}
form.hs-cf .hs-cf-property-icon {
	padding: 0;
}

/* text buttons */
form.hs-cf .hs-property-button:not(:has(.variation-price:empty)) {
	padding-bottom: 2px;
}
form.hs-cf .hs-property-button .variation-price:not(:empty)::after {
	content: "";
	border-top: 1.5px solid #0000001a;
	position: absolute;
	width: 100%;
	bottom: 1.55em;
}
form.hs-cf .hs-property-button:not(:has(.variation-price:empty)) {
	margin-bottom: 0.25em;
	cursor: pointer;
	overflow: hidden;
}

/* double color buttons */
form.hs-cf .hs-cf-parent-property-bundle-color:not(:has(.variation-price:empty)) {
  display: inline-grid;
  gap: 0.25em;
  text-align: center;
  padding: 0.15em;
  border-radius: 5px;
  height: calc(2.5em + 1.55em);
}

form.hs-cf .hs-cf-parent-property-bundle-color,
form.hs-cf .hs-cf-property-bundle-color {
  cursor: pointer;
}

form.hs-cf .hs-cf-parent-property-bundle-color .variation-price.variation-price:not(:empty) {
  padding-inline: 0.15em;
  padding-top: 0.20em;
  position: relative;
}

form.hs-cf .hs-cf-parent-property-bundle-color .variation-price:not(:empty)::after {
	content: "";
	border-top: 1.5px solid #0000001a;
	height: 100%;
	position: absolute;
	width: 100%;
	bottom: 0;
  left: 0;
}
form.hs-cf .hs-cf-parent-property-bundle-color:has(.hs-cf-property-input-bundle:checked) {
  box-shadow: none;
  border: 2px solid var(--clr-primary, #e68614);
}

form.hs-cf .hs-cf-parent-property-bundle-color {
  margin-left: 0.1rem;
  margin-bottom: 0.35rem;
  border: 2px solid #ddd;
  border-radius: 5px
}

/* common */
form.hs-cf .hs-cf-property-icon,
form.hs-cf .hs-property-button {
	cursor: pointer;
	overflow: hidden;
	border-radius: 5px;
	background-color: #fff;
	margin-bottom: 0.15em;
}
form.hs-cf .hs-property-button {
  margin-right: 0.1rem;
  margin-bottom: 0.35rem;
}
form.hs-cf .hs-cf-property-input + .hs-cf-property-icon {
  border: var(--size-cf-property-icon-border) solid #ddd;
}
form.hs-cf .hs-cf-property-input:checked + .hs-cf-property-icon {
  box-shadow: none;
  border: var(--size-cf-property-icon-border) solid var(--clr-cf-property-icon, #e68614);
}

form.hs-cf .hs-cf-property-color .variation-price:not(:empty),
form.hs-cf .hs-cf-property-icon .variation-price:not(:empty),
form.hs-cf .hs-property-button .variation-price:not(:empty) {
	display: flex;
	align-items: flex-end;
	justify-content: center;
	height: 100%;
	line-height: 1.5;
	position: relative;
	padding-top: 0.4em;
	padding-inline: 0.15em;
}

form.hs-cf .variation-price {
	z-index: 1;
	font-weight: 400;
}
/* ========================================================================== */
/* END - Different price for variations */

