:root {
	--padding: clamp(0.8125rem, 0.769rem + 0.2174vw, 0.9375rem);
	--swiper-theme-color: var(--clr-one);

	/* accent colors */
	--clr-one: #ff5b00;
	--clr-two: #FFEEE6;
	--clr-three: #FDAD84;

	/* page background colors */
	--bg-clr-one: #fff;
	--bg-clr-two: #F5F5F5;

	/* other colors */
	--clr-dark: #242427;
	--clr-black: #000;
	--clr-white: #fff;
	--clr-red: #ed2e38;
	--clr-border: #F2F2F2;
	--clr-border-dark: #E4E4E4;

	/* decorations */
	--radius: 0.5em;
	--radius-big: 0.75em;
	--radius-circle: 10em;
	--shadow: 0 .5rem 1rem rgba(0, 0, 0, .15);
	--transition-time: 0.2s;
	--transition-function: cubic-bezier(0.4, 0, 0.2, 1);
	--header-height: 3.3125rem;
	--sticky-bar-height: 4.25rem;

	/* gaps */
	--gap-xxl: clamp(2.25rem, 1.9457rem + 1.5217vw, 3.125rem);
	--gap-xl: clamp(1.5rem, 1.3696rem + 0.6522vw, 1.875rem);
	--gap-l: clamp(1.25rem, 1.163rem + 0.4348vw, 1.5rem);
	--gap-m: clamp(1.0625rem, 0.9973rem + 0.3261vw, 1.25rem);
	--gap-s: clamp(0.75rem, 0.6848rem + 0.3261vw, 0.9375rem);
	--gap-xs: clamp(0.625rem, 0.5815rem + 0.2174vw, 0.75rem);
	--gap-xxs: clamp(0.5rem, 0.4565rem + 0.2174vw, 0.625rem);
	
	/* Fluid scale */
	/* @link https://utopia.fyi/type/calculator?c=320,14,1.2,1240,16,1.25,8,4,&s=0.75|0.5|0.25,1.5|2|3|4|6,s-l&g=s,l,xl,12 */
	--step--5: clamp(0.4096rem, 0.4263rem + -0.0215vw, 0.422rem);		/* 6.55 p */
	--step--4: clamp(0.5064rem, 0.5044rem + 0.0098vw, 0.512rem);		/* 8.19 p */
	--step--3: clamp(0.6076rem, 0.5964rem + 0.0563vw, 0.64rem);			/* 10.24 p */
	--step--2: clamp(0.7292rem, 0.7045rem + 0.1232vw, 0.8rem);			/* 12.80 p */
	--step--1: clamp(0.8021rem, 0.768rem + 0.1703vw, 0.9rem);				/* 14.40 p */
	--step-0: clamp(0.875rem, 0.8315rem + 0.2174vw, 1rem);					/* 16.00 p */
	--step-1: clamp(0.9625rem, 0.906rem + 0.2826vw, 1.125rem);			/* 18.00 p */
	--step-2: clamp(1.05rem, 0.9804rem + 0.3478vw, 1.25rem);				/* 20.00 p */
	--step-3: clamp(1.26rem, 1.1548rem + 0.5261vw, 1.5625rem);			/* 25.00 p */
	--step-4: clamp(1.386rem, 1.2567rem + 0.6466vw, 1.7578rem);			/* 28.12 p */
	--step-5: clamp(1.512rem, 1.3586rem + 0.7672vw, 1.9531rem);			/* 31.25 p */
	--step-6: clamp(1.8144rem, 1.5963rem + 1.0904vw, 2.4414rem);		/* 39.06 p */
	--step-6_5: clamp(1.9959rem, 1.7347rem + 1.3056vw, 2.7466rem);	/* 43.94 p */
	--step-7: clamp(2.1773rem, 1.8731rem + 1.5208vw, 3.0518rem);		/* 48.83 p */
	--step-8: clamp(2.6127rem, 2.1947rem + 2.0904vw, 3.8147rem);		/* 61.04 p */
	--step-9: clamp(3.1353rem, 2.5673rem + 2.8402vw, 4.7684rem);		/* 76.29 p */
	--step-10: clamp(3.7623rem, 2.9978rem + 3.8228vw, 5.9605rem);		/* 95.37 p */
}

/* reset */
/* ========================================================================== */

html {
	box-sizing: border-box;
}

*, *:before, *:after {
	box-sizing: inherit;
}

img, video {
	max-width: 100%;
	vertical-align: middle;
}

h1, h2, h3, h4, h5, h6 {margin-block: 0;font-weight: 850;text-wrap: balance}

a {
	color: inherit;
}
.material-symbols-outlined.filled {
  font-variation-settings:
  'FILL' 1,
  'wght' 400,
  'GRAD' 0,
  'opsz' 24
}
.material-symbols-outlined {
  font-variation-settings:
  'FILL' 0,
  'wght' 400,
  'GRAD' 0,
  'opsz' 24
}

/* general */
/* ========================================================================== */
body {
	font-family: "Mulish", sans-serif;
	font-weight: 400;
	line-height: 1.4;
	scroll-behavior: smooth;
	/* overflow-x: hidden; */
	color: #000;
	background-color: var(--bg-clr-one);
	font-size: var(--step-0, 1rem);
}
.main {
	margin: 0 auto;
	padding-top: var(--header-height);
}
.section {
	padding-block: calc(var(--padding) * 2.5);
	padding-inline: var(--padding);
}
.container {
	margin-inline: auto;
	max-width: 75rem;
}
.container-wide {
	margin-inline: auto;
	max-width: 120rem;
}

/* @media (max-width: 95.9375rem) {
	.container {
		max-width: 81.25rem;
	}
}
@media (max-width: 85.375rem) {
	.container {
		max-width: 75rem;
	}
} */

@media (max-width: 47.9375rem) {
	.hidden-mobile {display: none!important;}
}
@media (min-width: 48rem) and (max-width: 63.9375rem) {
	.hidden-tablet {display: none!important;}
}
@media (min-width: 64rem) {
	.hidden-desktop {display: none!important;}
	.section {
		padding-inline: calc(var(--padding) * 2.5);
	}
}

@media (max-width: 35.9375rem) {
	.section {
		padding-block: calc(var(--padding) * 1.75);
	}
}

@media (max-width: 47.9375rem) {
	body {
		font-size: var(--step-1);
	}
}

/* hr*/
/* ========================================================================== */
hr {
	margin-block: var(--padding);
	border: 0;
	border-top: 0.0625rem solid var(--clr-border);
}

/* other */
/* ========================================================================== */
.accent {
	color: var(--clr-one);
}

/* buttons */
/* ========================================================================== */
.btn {
	display: inline-flex;
	gap: 0.5em;
	color: var(--clr-one);
	background-color: #fff;
	border: .15rem solid var(--clr-one);
	/* box-shadow: 0 0 0 .15rem var(--clr-one); */
	padding: 0.65em 1.65em;
	border-radius: var(--radius);

	font-family: inherit;
	font-weight: 700;
	font-size: var(--step-1);
	text-decoration: none;
	text-align: center;
	cursor: pointer;

	align-items: center;
	justify-content: center;
	justify-items: center;
	align-content: center;

	transition: background-color var(--transition-function) var(--transition-time, 0.25s),
							color var(--transition-function) var(--transition-time, 0.25s),
							fill var(--transition-function) var(--transition-time, 0.25s),
							box-shadow var(--transition-function) var(--transition-time, 0.25s);
}
.btn--bg {
	color: #fff;
	background-color: var(--clr-one);
}
.btn--black {
	color: #fff;
	background-color: #121212;
	box-shadow: none;
}
.btn img,
.btn svg {
	width: 1em;
	height: 1em;
	object-fit: contain;
	vertical-align: middle;
	color: currentColor;
	fill: currentColor;
}
.btn:hover,
.btn.active {
	color: var(--clr-one);
	background-color: #fff;
}
.btn--black:hover {
	background-color: #000;
}

.btn-arw {
	position: relative;
	/* padding: 12px 30px; */
	padding: 0.8em 1.65em;
	background-color: var(--clr-one);
	color: white;
	border: none;
	border-radius: var(--radius);
	font-family: inherit;
	font-weight: 700;
	font-size: var(--step-1);
	text-decoration: none;
	text-align: center;

	cursor: pointer;
	overflow: hidden;
	transition: padding 0.3s ease;
}
.btn-arw span {
	display: inline-block;
}
.btn-arw::after {
	content: '';
	position: absolute;
	right: -2rem;
	top: 50%;
	transform: translateY(-50%);
	width: 2rem;
	height: .65rem;
	background-color: white;
	clip-path: polygon(0% 32%, 70% 32%, 70% 0%, 100% 50%, 70% 100%, 70% 68%, 0% 68%);
	opacity: 0;
	transition: right 0.3s ease, opacity 0.3s ease;
}
.btn-arw:hover {
	padding-right: 55px;
}
.btn-arw:hover::after {
	right: 15px;
	opacity: 1;
}

/* header */
/* ========================================================================== */
.header {
	position: fixed;
	z-index: 15;
	width: 100%;
}
.header__inner {
	background: #fff;
	box-shadow: 0 .25rem 1.25rem #0000000a;
	border-bottom: .0625rem solid #eee;
	padding-inline: var(--padding);
	padding-block: 1rem;
}
.header__content {
	display: grid;
	grid-template-columns: repeat(3, auto);
	grid-template-rows: auto;
	column-gap: 1rem;
	justify-content: space-between;
	align-items: center;
}

.header__menu {
	grid-column: 1 / -1;
}
.hamburger {
}
.header__logo {
	grid-column: 2 / 3;
	grid-row: 1 / 1;
}
.header__cart {
	grid-column: 3 / 4;
	grid-row: 1 / 1;
}

.header__logo {
	line-height: 1;
}
.header__logo-img {
	width: 8.125rem;
}
.header__menu {
	padding-left: 0;
	list-style: none;
	margin: 0;
	max-height: 0;
	transition: max-height var(--transition-time, 0.25s) ease-in-out;
	overflow: hidden;
}
.header__menu-item {}
.header__menu-link {
	display: inline-block;
	padding-block: 0.45em;
	text-decoration: none;
	text-transform: uppercase;
	line-height: 1;
}
.header__hamburger-btn {
	display: none;
}
.header__hamburger-icon {
	padding-block: .9375rem;
	position: relative;
	cursor: pointer;
}
.header__icon {
	width: 1.375rem;
	height: .125rem;
	display: block;
	background: #333;
	position: relative;
	border-radius: .3125rem;
	transition: background var(--transition-time, 0.25s) ease-in-out;
}
.header__icon::before,
.header__icon::after {
	content: '';
	width: 100%;
	height: 100%;
	display: block;
	background: #333;
	position: absolute;
	border-radius: .3125rem;
	transition: all var(--transition-time, 0.25s) ease-in-out;
}
.header__icon::before {
	top: -0.4375rem;
}
.header__icon::after {
	top: .4375rem;
}
.header__hamburger-btn:checked~.header__menu {
	max-height: 15rem;
}
.header__hamburger-btn:checked~.header__hamburger-icon .header__icon {
	background: transparent;
}
.header__hamburger-btn:checked~.header__hamburger-icon .header__icon::before {
	transform: rotate(45deg);
	top: 0;
}
.header__hamburger-btn:checked~.header__hamburger-icon .header__icon::after {
	transform: rotate(-45deg);
	top: 0;
}

@media (max-width: 47.9375rem) {
	.header__menu-item:first-child {
		margin-top: 1rem;
	}
}

/* @media (min-width: 48rem) {
	.header__menu {
		display: flex;
		gap: 1.5rem;
		max-height: none;
		grid-row: 1;
	}

	.header__hamburger-icon {
		display: none;
	}
} */

@media (min-width: 64rem) {
	.header__menu {
		display: flex;
		gap: 0 1rem;
		max-height: none;
		width: 445px;
		flex-wrap: wrap;
		grid-row: 1;
	}
	.header__content {
		justify-content: initial;
	}
	.header__cart {
		justify-self: end;
	}
	.header__hamburger-icon {
		display: none;
	}
}

/* --- */
.header {transition: transform 0.3s ease-in-out;}
.header.hidden {transform: translateY(-100%);}

/* horizontal ticker */
/* ========================================================================== */
.horizontal-ticker {
	overflow-x: hidden;
	max-width: 100%;
	color: #fff;
	background-color: #000;
	padding-block: 1rem;
	font-weight: 800;
}
.horizontal-ticker__container {
	display: flex;
	align-items: center;
	width: fit-content;
	gap: 50px;
}
.horizontal-ticker__item {
	margin: 0;
	line-height: 1;
	white-space: nowrap
}
/* START horizontal-ticker animation */
.horizontal-ticker__container {animation: mobileHorTickersections 75s linear infinite normal forwards;}
.horizontal-ticker-sections:hover .horizontal-ticker__container {animation-play-state: paused}
@media screen and (min-width: 750px) {.horizontal-ticker__container {animation-name: desktopHorTickersections}}
@keyframes mobileHorTickersections {to {transform: translateX(calc(-50% - 15.0px))}}
@keyframes desktopHorTickersections {to {transform: translateX(calc(-50% - 25.0px))}}
/* END horizontal-ticker animation */

@media (max-width: 63.9375rem) {
	.horizontal-ticker {
		font-weight: 700;
		padding-block: 0.75rem;
	}
}

.header .horizontal-ticker {
	transition: all 0.25s ease-out;
}
.ticker-hidden {
	transform: translateY(-100%);
	opacity: 0;
	visibility: hidden;
	max-height: 0;
	padding-top: 0;
	padding-bottom: 0;
	margin-top: 0;
	margin-bottom: 0;
}

/* product rating */
/* ========================================================================== */
.product-rating {
	display: inline-flex;
	flex-wrap: wrap;
	align-items: center;
	flex-grow: 0;
	gap: var(--gap-xxs, .625rem);
	font-size: var(--step--1, .875rem);
}
.product-rating__img {
	width: 6.25rem;
	object-fit: contain;
}
.product-rating__txt {}

/* section hero */
/* ========================================================================== */
.sct-hero {}
.sct-hero__content {
	display: grid;
	grid-template-columns: repeat(2, minmax(12.5rem, 100%));
	gap: var(--gap-xxl);
	position: relative;
	/* align-items: center; */
}
.sct-hero__content-row.--sticky {
	position: sticky;
	top: calc(var(--header-height, 4rem) + var(--padding));
	align-self: start;
}
.sct-hero__content-row {
	width: 100%;
}
.sct-hero__title {
	font-size: var(--step-6);
}
.sct-hero__descr {
	font-size: var(--step-0);
	font-weight: 700;
	letter-spacing: 0.03em;
}

.sct-hero__offer-ends {
	display: flex;
	align-items: center;
	gap: 1ch;
	margin-bottom: 1rem;
	font-weight: 800;
}

.sct-hero__offer-ends::before,
.sct-hero__offer-ends::after {
	content: "";
	flex-grow: 1;
	height: 2px;
	/* background-color: #FFCDBA; */
	background-color: var(--clr-one);
}

.sct-hero__btn {
	width: 100%;
	font-size: var(--step-2);
	text-transform: uppercase;
	margin-top: var(--gap-xl);
}

@media (max-width: 47.9375rem) {
	.sct-hero__logo {
		margin-bottom: calc(var(--padding)* 1.75);
	}
	.sct-hero__content {
		display: flex;
		flex-direction: column;
		gap: var(--gap-xl);
	}
	.sct-hero__content-row.--sticky {
		position: unset;
		width: 100%;
	}
	.sct-hero__descr {
		font-size: var(--step-0);
	}
	.sct-hero__img {
		width: 29.375rem;
	}
	.sct-hero__features {
		gap: var(--gap-s);
	}
	.sct-hero__features-img {
		width: 3.125rem;
	}
	.sct-hero__features-text {
		letter-spacing: normal;
	}
}


/* START section hero - gallery slider */
/* ========================================================================== */

/* Swiper slider - base styles */
/* ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~ */
.swiper {
	width: 100%;
	height: 100%;
	border-radius: var(--slider-radius);
	box-sizing: border-box;
}
.swiper-slide {
	overflow: hidden;
	border-radius: var(--slider-radius);
}
.swiper-slide img {
	max-width: 100%;
	object-fit: contain;
	vertical-align: middle;
}

/* Main Slider Styles */
/* ------------------------- */
.gallery-slider {
	width: 100%;
	margin-bottom: .625rem; /* Space between main slider and thumbs */
}
.gallery-slider .swiper-slide {
	display: flex;
	justify-content: center;
	align-items: center;
	background-color: #eee;
}

/* Thumbs Slider Styles */
/* ------------------------- */
.gallery-thumbs {}
.gallery-thumbs .swiper-slide {
	box-sizing: border-box; /* Include padding/border */
	display: flex;
	justify-content: center;
	align-items: center;
	cursor: pointer;
	font-size: .75rem;
	background-color: #eee;
	/* opacity: 0.4; */
	text-align: center;
}
.gallery-thumbs .swiper-slide-thumb-active {
	opacity: 1;
	border: .125rem solid var(--slider-color); /* Highlight active thumb */
}

/* Swiper slider - advanced styles and effects */
/* ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~ */
.gallery-container {
	--slider-color: var(--clr-one, #0133aa);
	/* --slider-radius: 0.5rem; */
	--swiper-navigation-color: var(--slider-color);
	--swiper-pagination-color: var(--slider-color);
	--swiper-navigation-sides-offset: 1rem;
	--swiper-thumbnails-size: 4.0625rem;
}
.gallery-container .swiper-button-next, .gallery-container .swiper-button-prev {
	--swiper-nav-button-size: clamp(1.875rem, 1.6023rem + 1.3636vw, 2.8125rem);
	top: calc(50% + (var(--swiper-nav-button-size) / 4));
	aspect-ratio: 1 / 1;
	width: var(--swiper-nav-button-size);
	height: var(--swiper-nav-button-size);
	background: var(--slider-color);
	color: #fff;
	border-radius: 3em;
}
.gallery-container .swiper-button-next:after, .gallery-container .swiper-button-prev:after{
	font-size: 0.625rem;
	line-height: 1;
	text-align: center;
}
.gallery-container .swiper .swiper-button-prev.swiper-button-disabled,
.gallery-container .swiper .swiper-button-next.swiper-button-disabled {
	opacity: 0.75;
}

/* animation for nav buttons */
/* ------------------------- */
.gallery-container .swiper .swiper-button-next, .gallery-container .swiper .swiper-button-prev {
	opacity: 0;
	transition: opacity ease-in-out var(--transition-time, 0.25s),
							box-shadow ease-in-out var(--transition-time, 0.25s),
							transform ease-in-out var(--transition-time, 0.25s);
}
.gallery-container .swiper .swiper-button-prev {transform: translate3d(-200%, 0, 0)}
.gallery-container .swiper .swiper-button-next {transform: translate3d(200%, 0, 0)}
.gallery-container .swiper:hover .swiper-button-next, .gallery-container .swiper:hover .swiper-button-prev {
	opacity: 1;
	transform: none;
}
.gallery-container .swiper .swiper-button-prev:hover, .gallery-container .swiper .swiper-button-next:hover {
	box-shadow: 0 0 0 .2rem var(--slider-color);
}


@media (min-width: 767px) {
	.gallery-slider .swiper-wrapper {
		display: grid;
		grid-template-columns: repeat(2, 1fr);
		gap: var(--step--3);
	}
	.gallery-slider .swiper-slide:first-child {
		grid-column: 1 / -1;
	}
	.gallery-thumbs {
		display: none;
	}
}

@media (max-width: 767px) {
	.gallery-slider {
		margin-inline: calc(var(--padding) * -1);
		width: calc(100% + (var(--padding) * 2));
	}
}
/* ========================================================================== */
/* END section hero - gallery slider */



/* micromodal */
/* ========================================================================== */
.micromodal {
	display: none;
	--padding: var(--step-1);
}
.micromodal.is-open {
	display: block;
}
.micromodal__overlay {
	position: fixed;
	top: 0;
	left: 0;
	right: 0;
	bottom: 0;
	display: flex;
	justify-content: center;
	align-items: center;
	background: rgba(0,0,0,0.65);
	z-index: 3;
}
.micromodal__container {
	box-sizing: border-box;
	overflow-y: auto;
	max-width: 500px;
	max-height: 100vh;
	padding: var(--padding);
	background-color: #fff;
	border-radius: var(--radius-big);
	position: relative;
}
.micromodal__btn-close {
	display: block;
	position: absolute;
	right: 0;
	margin-right: var(--padding);
	background: transparent;
	border: 0;
	padding: 0;
	line-height: 1;
	/* background-color: red; */
	cursor: pointer;
}
.micromodal__btn-close svg {
	height: 1.15rem;
	width: 1.15rem;
}

.micromodal[aria-hidden="false"] .micromodal__overlay {
	animation: microModalFadeIn .2s cubic-bezier(0.0, 0.0, 0.2, 1);
}
.micromodal[aria-hidden="false"] .micromodal__container {
	animation: microModalSlideIn .2s cubic-bezier(0, 0, .2, 1);
}
.micromodal .micromodal__container,
.micromodal .micromodal__overlay {
	will-change: transform;
}
@keyframes microModalFadeIn {
		from { opacity: 0; }
			to { opacity: 1; }
}
@keyframes microModalSlideIn {
	from { transform: translateY(15%); }
		to { transform: translateY(0); }
}

/* modal-size */
/* - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -  */
.modal-size {
	margin-bottom: 1rem;
}
.modal-size__title {
	margin-bottom: 0.75rem;
}
.modal-size__btn {
	display: flex;
	align-items: center;
	text-decoration: none;
	gap: 0.5ch;
	font-size: var(--step--1);
}
.modal-size__btn-text {
	text-decoration: underline;
}

.modal-size .size-table tr:first-child td,
.modal-size .size-table tr:first-child:hover td {
	color: #fff!important;
	background-color: #000!important;
	border-color: #555555!important;
}
.modal-size .size-table th,
.modal-size .size-table td:first-child {
	color: #292938!important;
	background-color: transparent!important;
}
.modal-size .size-table tr:hover td {
	background-color: #fff!important;
}

/* remains (Only XX pairs left in stock!) */
/* ========================================================================== */
.remains {text-align: center;}
.remains__text {}
.remains__dot{display: inline-block; width: 10px; height: 10px; background-color: #ffc107; border-radius: 50%; margin-right: 8px;}
.remains__dot{animation:pulse 1.5s infinite ease-in-out;}
@keyframes pulse{0%{transform:scaleX(1);}50%{transform:scale3d(1.05,1.05,1.05);}to{transform:scaleX(1);}}
@keyframes pulse{0%{transform:scale(1);opacity:1;}50%{transform:scale(1.6);opacity:0.5;}100%{transform:scale(1);opacity:1;}}


/* seller benefits */
/* ========================================================================== */
.seller-benefits {
	list-style: none;
	padding: 0;
	display: grid;
	grid-template-columns: repeat(3, 1fr);
	gap: var(--gap-xxs);
}
.seller-benefits__item {
	display: grid;
	gap: var(--gap-xxs);
	text-align: center;
	justify-items: center;
}
.seller-benefits__item-icon {
	font-size: 2.25rem;
	width: 2.25rem;
    height: 2.25rem;
}
.seller-benefits__item-text {
	text-wrap: balance;
}

/* acrd */
/* ========================================================================== */
.acrd__item {
	display: block;
	overflow: hidden;
	border-bottom: .0625rem solid var(--clr-border);
}
.acrd__item:first-child {
	border-top: .0625rem solid var(--clr-border);
}
.acrd__item summary::-webkit-details-marker {display: none;}
.acrd__item summary::-moz-list-bullet {list-style-type: none;}
.acrd__item summary::marker {display: none;}
.acrd__item summary {
	display: block;
	padding: 0.75rem 0;
	padding-right: 1.5rem;
	font-size: inherit;
	font-weight: 700;
	cursor: pointer;
	position: relative;
	line-height: 1;
}
.acrd__item summary::before {
	top: 50%;
	right: 0.5em;
	transform: translateY(-50%);
	position: absolute;
	/* content: "+"; */
	content: url('data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="%23292929"><path d="M15.666 7H9V.334A.333.333 0 0 0 8.666 0H7.334A.333.333 0 0 0 7 .334V7H.334A.333.333 0 0 0 0 7.334v1.332C0 8.851.149 9 .334 9H7v6.667c0 .184.149.333.334.333h1.332A.333.333 0 0 0 9 15.666V9h6.667A.333.333 0 0 0 16 8.666V7.334A.333.333 0 0 0 15.666 7z" style="stroke-width:.5"/></svg>');
}
.acrd__item[open] > summary::before {
	/* content: "–"; */
	content: url('data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="%23292929"><path d="M15.667 6.889H.333c-.184 0-.333.166-.333.37v1.482c0 .204.15.37.333.37h15.334c.184 0 .333-.166.333-.37V7.259c0-.204-.15-.37-.333-.37Z" style="stroke-width:.444444"/></svg>');
}
.acrd__item summary ~ * {
	margin-top: 0;
	margin-bottom: 1.25rem;
}
.acrd__item[open] summary ~ * {
	animation: sweep 0.3s ease-in-out;
}

@keyframes sweep {
	0%    {opacity: 0;}
	100%  {opacity: 1;}
}

/* .acrd__item summary:focus {
	outline: none;
} */

.acrd__heading {
	display: inline-flex;
	align-items: center;
	gap: var(--gap-xxs);
}


/* timer */
/* ========================================================================== */
.timer {
	margin-block: var(--gap-m);
}
.timer-title {
	display: block;
	font-size: var(--step-1);
	text-align: center;
	margin-bottom: var(--gap-xxs);
}
.timer-body {
	display: flex;
	justify-content: center;
	align-items: center;
	gap: var(--gap-xxs);
}
.time-block {
	text-align: center;
}
.time-block span {
	display: block;
	font-size: 2rem;
	font-weight: bold;
	color: white;
	background-color: #ff5c00;
	width: 3.75rem;
	height: 2.5rem;
	line-height: 2.5rem;
	border-radius: .625rem;
	margin-bottom: .625rem;
}
.time-block p {
	margin-block: 0;
}

/* section reviews */
/* ========================================================================== */
/* section reviews - slider */
/* - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -  */
.hero-reviews.swiper {
	height: auto;
}
.hero-reviews .swiper-wrapper {
	height: auto;
}
.hero-reviews-pagination {
	text-align: center;
	margin-inline: auto;
	transform: unset!important;
	margin-top: .625rem;
}
.hero-reviews-pagination .swiper-pagination-bullet-active {
	background: #000;
}
/* - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -  */

.hero-reviews {}
.hero-reviews-item {
	display: flex;
	gap: var(--gap-m);
	background-color: var(--bg-clr-two);
	padding: .5rem .625rem;
	border-radius: var(--radius-big);
	cursor: grab;
}
.hero-reviews__photo {}
.hero-reviews__photo-img {
	width: 3.125rem!important;
	height: 3.125rem!important;
	border-radius: 50%;
	max-width: unset!important;
}
.hero-reviews__descr {}
.hero-reviews__descr-text {
	font-size: var(--step--1);
	text-align: left;
}
.hero-reviews__descr-text p {
	margin-block: 0;
}
.hero-reviews__descr-author {
	display: flex;
	align-items: center;
	gap: 0.5ch;
	font-size: var(--step--2);
	color: #797979;
	border-top: 1px solid var(--clr-border-dark);
	padding-top: .5rem;
	margin-top: .5rem;
}
.hero-reviews__descr-rating {
	height: .6875rem!important;
	width: auto!important;
}
.hero-reviews__descr-verif {
