/* section comparison */
/* ========================================================================== */

.sct-comparison {}
.sct-comparison__content {
	display: grid;
	grid-template-columns: repeat(2, 1fr);
	gap: var(--gap-xxl);
	align-items: center;
	justify-items: center
}
.sct-comparison__illustr {}
.sct-comparison__descr {
	text-align: center;
	margin-inline: auto;
	text-wrap: balance;
}
.sct-comparison__title {
	font-size: var(--step-6_5);
	/* max-width: 16ch; */
	margin-inline: auto;
	line-height: 1.2;
}
.sct-comparison__text {
	line-height: 1.75;
}

/* - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -  */
.comparison-benefits {
	list-style: none;
	padding: 0;
	display: grid;
	grid-template-columns: repeat(4, 1fr);
	gap: var(--gap-xxs);
	margin-top: var(--gap-xl);
}
.comparison-benefits__item {
	display: grid;
	gap: var(--gap-xxs);
	text-align: center;
	justify-items: center;
}
.comparison-benefits__item-icon {
	color: var(--clr-one);
	font-size: 2.75rem;
	width: 2.75rem;
	height: 2.75rem;
}
.comparison-benefits__item-text {
	text-wrap: balance;
	line-height: 1.75;
}
/* - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -  */
.comparison {
	max-width: 450px;
	overflow: hidden;
	margin: 0 auto;
}
.comparison__container {
	position: relative;
	display: flex;
}
.comparison__image {
	width: 100%;
	height: 100%;
	object-fit: cover;
	object-position: left;
}
.comparison__text {
	position: absolute;
	top: 0;
	font-weight: 600;
	font-size: 14px;
	color: var(--clr-white);
	background: var(--clr-one);
	padding: 3px 13px;
}
.comparison__text.before {
	left: 0;
}
.comparison__text.after {
	right: 0;
}
.comparison__image.before {
	position: absolute;
	top: 0;
	width: 50%;
}
.comparison__range {
	position: absolute;
	inset: 0;
	opacity: 0;
	cursor: col-resize;
}

.comparison__slider-line,
.comparison__slider-icon {
  touch-action: none;
  -webkit-user-select: none;
  user-select: none;
}


.comparison__slider-line {
	position: absolute;
	height: 100%;
	width: 3px;
	left: 50%;
	transform: translateX(-50%);
}
.comparison__slider-line::before,
.comparison__slider-line::after {
	position: absolute;
	content: "";
	width: 100%;
	height: calc(50% - 25px);
	background: var(--clr-black);
}
.comparison__slider-line::before {
	top: 0;
}
.comparison__slider-line::after {
	bottom: 0;
}
.comparison__slider-icon {
	position: absolute;
	left: 50%;
	top: 50%;
	height: 50px;
	width: 50px;
	border: 3px solid var(--clr-black);
	border-radius: 50%;
	background: #ffffff33;
	backdrop-filter: blur(2px);
	transform: translate(-50%, -50%);
}
.comparison__slider-icon::before,
.comparison__slider-icon::after {
	position: absolute;
	content: "";
	top: 50%;
	border: 10px solid transparent;
	border-bottom-width: 0px;
	border-right-width: 0px;
	transform: translate(-50%, -50%) rotate(45deg);
}
.comparison__slider-icon::before {
	left: 30%;
	border-left-color: var(--clr-black);
}
.comparison__slider-icon::after {
	left: 70%;
	border-top-color: var(--clr-black);
}

@media (max-width: 63.9375rem) {}
@media (max-width: 47.9375rem) {
	.sct-comparison__content {
		display: flex;
		flex-direction: column-reverse;
		gap: var(--gap-l);
	}
	.comparison-benefits {
		grid-template-columns: repeat(2, 1fr);
	}
}

