		margin-top: 1.5rem;
	}
}
@media (max-width: 47.9375rem) {}

/* section reviews */
/* ========================================================================== */
.sct-results {}
.sct-results__content {
	display: grid;
	grid-template-columns: repeat(2, 1fr);
	gap: var(--gap-xxl);
	align-items: center;
	justify-items: center
}
.sct-results__descr {
	text-align: center;
