}
.sct-results__title {
	font-size: var(--step-6_5);
	/* max-width: 16ch; */
	margin-inline: auto;
	line-height: 1.2;
}
.sct-results__text {
	line-height: 1.75;
}
.sct-results__illustr {}

.results {}
.results__rows-container {
	margin-bottom: 1rem;
}
.results__percentage {
	--border-width: .45rem;
	width: 4.375rem;
	height: 4.375rem;
	display: flex;
	align-items: center;
	justify-content: center;
	flex-shrink: 0;
	text-align: center;
	border-radius: 50%;
	position: relative;
	z-index: 0;
}
.results__percentage:before {
	content: "";
	display: block;
	position: absolute;
	top: 0;
	left: 0;
	bottom: 0;
	right: 0;
	border-radius: 50%;
	z-index: -2;
	background: conic-gradient(from 0deg at 50% 50%, #ff5b00 0%, #ff5b00 var(--percentage), #fff var(--percentage), #fff 100%);
}
.results__percentage:after {
	content: "";
	display: block;
	position: absolute;
	top: var(--border-width);
	left: var(--border-width);
	bottom: var(--border-width);
	right: var(--border-width);
	border-radius: 50%;
	z-index: -1;
	background: #fff;
}
.results__percentage p {
