<script>
  let data = Array.from(document.querySelectorAll('.accordion .accordion__item')),
    step = 10,
    item = 0;

  data.slice(step).forEach(e => e.style.display = 'none');
  item += step;
  if(!!document.querySelector('#more-faq')){ 
      document.querySelector('#more-faq').addEventListener('click', function(e){
        let tmp = data.slice(item, item + step);
        tmp.forEach(e => e.style.display = 'block');
        item += step;

        if(tmp.length < 10)
        this.remove();
      });
  }
</script>



